class Solution {
    public int countWinningSequences(String s) {
        int n = s.length();
        int MOD = (int) (1e9 + 7);
        long[][] dp = new long[n][3];
        int prev = -1;
        for (int i = 0; i < n; i++) {
            int curr = getState(s.charAt(i));
            if (i == 0) {
                dp[i][0] = dp[i][1] = dp[i][2] = 1;
            } else {
                for (int j = 0; j < 3; j++) {
                    for (int k = 0; k < 3; k++) {
                        if (k == prev) continue;
                        if (getWinner(curr, k) == 1) {
                            dp[i][k] = (dp[i][k] + dp[i - 1][j]) % MOD;
                        }
                    }
                }
            }
            prev = curr;
        }
        long alice = 0, bob = 0;
        for (int i = 0; i < n; i++) {
            int aliceMove = getState(s.charAt(i));
            for (int bobMove = 0; bobMove < 3; bobMove++) {
                int winner = getWinner(aliceMove, bobMove);
                if (winner == 1) bob++;
                else if (winner == -1) alice++;
            }
        }
        long total = 0;
        for (int i = 0; i < 3; i++) {
            total = (total + dp[n - 1][i]) % MOD;
        }
        long ans = (total + MOD - pow(2, n, MOD)) % MOD;
        return (int) ans;
    }

    private int getState(char c) {
        if (c == 'F') return 0;
        if (c == 'W') return 1;
        return 2;
    }

    private int getWinner(int alice, int bob) {
        if (alice == bob) return 0;
        if ((alice == 0 && bob == 2) || (alice == 1 && bob == 0) || (alice == 2 && bob == 1)) return -1;
        return 1;
    }

    private long pow(int x, int n, int mod) {
        long res = 1;
        long a = x;
        while (n > 0) {
            if ((n & 1) == 1) res = (res * a) % mod;
            a = (a * a) % mod;
            n >>= 1;
        }
        return res;
    }
}
